/**
 * Instance discovery for Oracle tablespaces across all configured databases.
 *
 * Enumerates every tablespace of every database connection listed by
 * Oracle.Connections and returns a map of instance key -> display name. The key
 * "<dbid>,<tablespace>" is substituted into the DCI parameter
 * Oracle.TableSpace.*(<dbid>,<tablespace>); the value "<tablespace>@<dbid>" is
 * shown in the DCI description.
 */
instances = %{};
databases = $node.readAgentList("Oracle.Connections");
if (databases != null)
{
   for(db : databases)
   {
      tablespaces = $node.readAgentList("Oracle.TableSpaces(" .. db .. ")");
      if (tablespaces != null)
      {
         for(tablespace : tablespaces)
            instances[db .. "," .. tablespace] = tablespace .. "@" .. db;
      }
   }
}
return instances;
